    10→// distributed under the License is distributed on an "AS IS" BASIS,
    11→// WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
    12→// See the License for the specific language governing permissions and
    13→// limitations under the License.
    14→
    15→package snap
    16→
    17→import (
    18→	"errors"
    19→	"fmt"
    20→	"hash/crc32"
    21→	"os"
    22→	"path/filepath"
    23→	"sort"
    24→	"strconv"
    25→	"strings"
    26→	"time"
    27→
    28→	"go.uber.org/zap"
    29→
    30→	"go.etcd.io/etcd/client/pkg/v3/verify"
    31→	pioutil "go.etcd.io/etcd/pkg/v3/ioutil"
    32→	"go.etcd.io/etcd/pkg/v3/pbutil"
    33→	"go.etcd.io/etcd/server/v3/etcdserver/api/snap/snappb"
    34→	"go.etcd.io/etcd/server/v3/storage/wal/walpb"
    35→	"go.etcd.io/raft/v3"
    36→	"go.etcd.io/raft/v3/raftpb"
    37→)
    38→
    39→const snapSuffix = ".snap"
    40→
    41→var (
    42→	ErrNoSnapshot    = errors.New("snap: no available snapshot")
    43→	ErrEmptySnapshot = errors.New("snap: empty snapshot")
    44→	ErrCRCMismatch   = errors.New("snap: crc mismatch")
    45→	crcTable         = crc32.MakeTable(crc32.Castagnoli)
    46→
    47→	// A map of valid files that can be present in the snap folder.
    48→	validFiles = map[string]bool{
    49→		"db": true,
    50→	}
    51→)
    52→
    53→type Snapshotter struct {
    54→	lg  *zap.Logger
    55→	dir string
    56→}
    57→
    58→func New(lg *zap.Logger, dir string) *Snapshotter {
    59→	if lg == nil {
    60→		lg = zap.NewNop()
    61→	}
    62→	return &Snapshotter{
    63→		lg:  lg,
    64→		dir: dir,
    65→	}
    66→}
    67→
    68→func (s *Snapshotter) SaveSnap(snapshot raftpb.Snapshot) error {
    69→	if raft.IsEmptySnap(snapshot) {
    70→		return nil
    71→	}
    72→	return s.save(&snapshot)
    73→}
    74→
    75→func (s *Snapshotter) save(snapshot *raftpb.Snapshot) error {
    76→	start := time.Now()
    77→
    78→	fname := fmt.Sprintf("%016x-%016x%s", snapshot.Metadata.Term, snapshot.Metadata.Index, snapSuffix)
    79→	b := pbutil.MustMarshal(snapshot)
    80→	crc := crc32.Update(0, crcTable, b)
    81→	snap := snappb.Snapshot{Crc: &crc, Data: b}
    82→	d, err := snap.Marshal()
    83→	if err != nil {
    84→		return err
    85→	}
    86→	snapMarshallingSec.Observe(time.Since(start).Seconds())
    87→
    88→	spath := filepath.Join(s.dir, fname)
    89→
    90→	fsyncStart := time.Now()
    91→	err = pioutil.WriteAndSyncFile(spath, d, 0o666)
    92→	snapFsyncSec.Observe(time.Since(fsyncStart).Seconds())
    93→
    94→	if err != nil {
    95→		s.lg.Warn("failed to write a snap file", zap.String("path", spath), zap.Error(err))
    96→		rerr := os.Remove(spath)
    97→		if rerr != nil {
    98→			s.lg.Warn("failed to remove a broken snap file", zap.String("path", spath), zap.Error(rerr))
    99→		}
   100→		return err
   101→	}
   102→
   103→	snapSaveSec.Observe(time.Since(start).Seconds())
   104→	return nil
   105→}
   106→
   107→// Load returns the newest snapshot.
   108→func (s *Snapshotter) Load() (*raftpb.Snapshot, error) {
   109→	return s.loadMatching(func(*raftpb.Snapshot) bool { return true })
   110→}
   111→
   112→// LoadNewestAvailable loads the newest snapshot available that is in walSnaps.
   113→func (s *Snapshotter) LoadNewestAvailable(walSnaps []walpb.Snapshot) (*raftpb.Snapshot, error) {
   114→	return s.loadMatching(func(snapshot *raftpb.Snapshot) bool {
   115→		m := snapshot.Metadata
   116→		for i := len(walSnaps) - 1; i >= 0; i-- {
   117→			if m.Term == walSnaps[i].GetTerm() && m.Index == walSnaps[i].GetIndex() {
   118→				return true
   119→			}
   120→		}
   121→		return false
   122→	})
   123→}
   124→
   125→// loadMatching returns the newest snapshot where matchFn returns true.
   126→func (s *Snapshotter) loadMatching(matchFn func(*raftpb.Snapshot) bool) (*raftpb.Snapshot, error) {
   127→	names, err := s.snapNames()
   128→	if err != nil {
   129→		return nil, err
   130→	}
   131→	var snap *raftpb.Snapshot
   132→	for _, name := range names {
   133→		if snap, err = s.loadSnap(name); err == nil && matchFn(snap) {
   134→			return snap, nil
   135→		}
   136→	}
   137→	return nil, ErrNoSnapshot
   138→}
   139→
   140→func (s *Snapshotter) loadSnap(name string) (*raftpb.Snapshot, error) {
   141→	fpath := filepath.Join(s.dir, name)
   142→	snap, err := Read(s.lg, fpath)
   143→	if err != nil {
   144→		brokenPath := fpath + ".broken"
   145→		s.lg.Warn("failed to read a snap file", zap.String("path", fpath), zap.Error(err))
   146→		if rerr := os.Rename(fpath, brokenPath); rerr != nil {
   147→			s.lg.Warn("failed to rename a broken snap file", zap.String("path", fpath), zap.String("broken-path", brokenPath), zap.Error(rerr))
   148→		} else {
   149→			s.lg.Warn("renamed to a broken snap file", zap.String("path", fpath), zap.String("broken-path", brokenPath))
   150→		}
   151→	}
   152→	return snap, err
   153→}
   154→
   155→// Read reads the snapshot named by snapname and returns the snapshot.
   156→func Read(lg *zap.Logger, snapname string) (*raftpb.Snapshot, error) {
   157→	verify.Assert(lg != nil, "the logger should not be nil")
   158→	b, err := os.ReadFile(snapname)
   159→	if err != nil {
   160→		lg.Warn("failed to read a snap file", zap.String("path", snapname), zap.Error(err))
   161→		return nil, err
   162→	}
   163→
   164→	if len(b) == 0 {
   165→		lg.Warn("failed to read empty snapshot file", zap.String("path", snapname))
   166→		return nil, ErrEmptySnapshot
   167→	}
   168→
   169→	var serializedSnap snappb.Snapshot
   170→	if err = serializedSnap.Unmarshal(b); err != nil {
   171→		lg.Warn("failed to unmarshal snappb.Snapshot", zap.String("path", snapname), zap.Error(err))
   172→		return nil, err
   173→	}
   174→
   175→	if len(serializedSnap.Data) == 0 || serializedSnap.GetCrc() == 0 {
   176→		lg.Warn("failed to read empty snapshot data", zap.String("path", snapname))
   177→		return nil, ErrEmptySnapshot
   178→	}
   179→
   180→	crc := crc32.Update(0, crcTable, serializedSnap.Data)
   181→	if crc != serializedSnap.GetCrc() {
   182→		lg.Warn("snap file is corrupt",
   183→			zap.String("path", snapname),
   184→			zap.Uint32("prev-crc", serializedSnap.GetCrc()),
   185→			zap.Uint32("new-crc", crc),
   186→		)
   187→		return nil, ErrCRCMismatch
   188→	}
   189→
   190→	var snap raftpb.Snapshot
   191→	if err = snap.Unmarshal(serializedSnap.Data); err != nil {
   192→		lg.Warn("failed to unmarshal raftpb.Snapshot", zap.String("path", snapname), zap.Error(err))
   193→		return nil, err
   194→	}
   195→	return &snap, nil
   196→}
   197→
   198→// snapNames returns the filename of the snapshots in logical time order (from newest to oldest).
   199→// If there is no available snapshots, an ErrNoSnapshot will be returned.
   200→func (s *Snapshotter) snapNames() ([]string, error) {
   201→	dir, err := os.Open(s.dir)
   202→	if err != nil {
   203→		return nil, err
   204→	}
   205→	defer dir.Close()
   206→	names, err := dir.Readdirnames(-1)
   207→	if err != nil {
   208→		return nil, err
   209→	}
   210→	filenames, err := s.cleanupSnapdir(names)
   211→	if err != nil {
   212→		return nil, err
   213→	}
   214→	snaps := s.checkSuffix(filenames)
   215→	if len(snaps) == 0 {
   216→		return nil, ErrNoSnapshot
   217→	}
   218→	sort.Sort(sort.Reverse(sort.StringSlice(snaps)))
   219→	return snaps, nil
   220→}
   221→
   222→func (s *Snapshotter) checkSuffix(names []string) []string {
   223→	var snaps []string
   224→	for i := range names {
   225→		if strings.HasSuffix(names[i], snapSuffix) {
   226→			snaps = append(snaps, names[i])
   227→		} else {
   228→			// If we find a file which is not a snapshot then check if it's
   229→			// a valid file. If not throw out a warning.
   230→			if _, ok := validFiles[names[i]]; !ok {
   231→				s.lg.Warn("found unexpected non-snap file; skipping", zap.String("path", names[i]))
   232→			}
   233→		}
   234→	}
   235→	return snaps
   236→}
   237→
   238→// cleanupSnapdir removes any files that should not be in the snapshot directory:
   239→// - db.tmp prefixed files that can be orphaned by defragmentation
   240→func (s *Snapshotter) cleanupSnapdir(filenames []string) (names []string, err error) {
   241→	names = make([]string, 0, len(filenames))
   242→	for _, filename := range filenames {
   243→		if strings.HasPrefix(filename, "db.tmp") {
   244→			s.lg.Info("found orphaned defragmentation file; deleting", zap.String("path", filename))
   245→			if rmErr := os.Remove(filepath.Join(s.dir, filename)); rmErr != nil && !os.IsNotExist(rmErr) {
   246→				return names, fmt.Errorf("failed to remove orphaned .snap.db file %s: %w", filename, rmErr)
   247→			}
   248→		} else {
   249→			names = append(names, filename)
   250→		}
   251→	}
   252→	return names, nil
   253→}
   254→
   255→func (s *Snapshotter) ReleaseSnapDBs(snap raftpb.Snapshot) error {
   256→	dir, err := os.Open(s.dir)
   257→	if err != nil {
   258→		return err
   259→	}
   260→	defer dir.Close()
   261→	filenames, err := dir.Readdirnames(-1)
   262→	if err != nil {
   263→		return err
   264→	}
   265→	for _, filename := range filenames {
   266→		if strings.HasSuffix(filename, ".snap.db") {
   267→			hexIndex := strings.TrimSuffix(filepath.Base(filename), ".snap.db")
   268→			index, err := strconv.ParseUint(hexIndex, 16, 64)
   269→			if err != nil {
   270→				s.lg.Error("failed to parse index from filename", zap.String("path", filename), zap.String("error", err.Error()))
   271→				continue
   272→			}
   273→			if index < snap.Metadata.Index {
   274→				s.lg.Info("found orphaned .snap.db file; deleting", zap.String("path", filename))
   275→				if rmErr := os.Remove(filepath.Join(s.dir, filename)); rmErr != nil && !os.IsNotExist(rmErr) {
   276→					s.lg.Error("failed to remove orphaned .snap.db file", zap.String("path", filename), zap.String("error", rmErr.Error()))
   277→				}
   278→			}
   279→		}
   280→	}
   281→	return nil
   282→}
